/**
 * Shared randomness for the synthetic/channel paths. Box-Muller Gaussian over a
 * pluggable uniform source so the Mars-channel tests are deterministic (seeded)
 * while live synthesis stays on Math.random.
 */

export type UniformRng = () => number;

/** mulberry32 seeded PRNG -> uniform [0,1). Deterministic for tests. */
export function mulberry32(seed: number): UniformRng {
  let a = seed >>> 0;
  return () => {
    a = (a + 0x6d2b79f5) >>> 0;
    let t = a;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/** Standard-normal pair via Box-Muller from a uniform source. */
export function gaussianPairFrom(rng: UniformRng): [number, number] {
  const u = Math.max(Number.EPSILON, rng());
  const v = Math.max(Number.EPSILON, rng());
  const r = Math.sqrt(-2 * Math.log(u));
  return [r * Math.cos(Math.PI * 2 * v), r * Math.sin(Math.PI * 2 * v)];
}

/** Standard-normal pair on Math.random (live synthesis). */
export function gaussianPair(): [number, number] {
  return gaussianPairFrom(Math.random);
}
